add_action('init', 'session_start_for_user');
function session_start_for_user(){
   if(!session_id()) {
        session_start();
   }
}

// Register the user registration form shortcode
add_shortcode( 'register-form', 'my_custom_registration_form' );
function my_custom_registration_form() {
    // Registration Form HTML code goes here
    $output = '';
    
    if (isset($_POST['submit'])) {
        $username = $_POST["user_name"];
        $password = $_POST["user_pass"];
        // Hashing the password and storing it
        $hashed_password = wp_hash_password( $password );
        
        global $wpdb;
        $table_name = $wpdb->prefix . "custom_users"; 
      
        $wpdb->insert($table_name, array('user_login' => $username , 'user_pass' => $hashed_password));
    }
    
    $output .= '<form method="post" action="">';
    $output .= 'Username: <input type="text" name="user_name" /><br/>';
    $output .= 'Password: <input type="password" name="user_pass" /><br/>';
    $output .= '<input type="submit" name="submit" value="Register" />';
    $output .= '</form>';
    return $output;
}

// Register the user login form shortcode
add_shortcode( 'login-form', 'my_custom_user_login' );
function my_custom_user_login() {
    // Login Form HTML code goes here
    $output = '';
    
    if (isset($_POST['submit'])) {
        $username = $_POST["user_name"];
        $password = $_POST["user_pass"];
        
        global $wpdb;
        $table_name = $wpdb->prefix . "custom_users"; 
      
        $results = $wpdb->get_row($wpdb->prepare("SELECT * FROM $table_name WHERE user_login = %s", $username));
        
        if(!empty($results) && wp_check_password($password, $results->user_pass, $results->ID)) {
            $_SESSION['logged_in'] = 1;
            // Redirect to dashboard or home page based on your requirement
        } else {
            echo 'Invalid Username/Password';
        }
    }
    
    $output .= '<form method="post" action="">';
    $output .= 'Username: <input type="text" name="user_name" /><br/>';
    $output .= 'Password: <input type="password" name="user_pass" /><br/>';
    $output .= '<input type="submit" name="submit" value="Login" />';
    $output .= '</form>';
    return $output;
}
